import React, { useState, useEffect } from 'react';
import { initializeApp } from 'firebase/app';
import { getMessaging, getToken, onMessage } from 'firebase/messaging';
import { Bell, BellRing, Image as ImageIcon, Clock, ShieldAlert, Terminal, MessageSquareWarning, VolumeX, RefreshCw } from 'lucide-react';

const firebaseConfig = {
  apiKey: "AIzaSyB3o2kr0PBD-LXXO_loHH_lhbBd8SrH9Pc",
    authDomain: "war-control-push.firebaseapp.com",
      projectId: "war-control-push",
        storageBucket: "war-control-push.firebasestorage.app",
          messagingSenderId: "1074882873916",
            appId: "1:1074882873916:web:24679bbdf9ce78f0329139"
            };

            const VAPID_KEY = "BBSuTkcsSNM2EDOuFwIx9sj9WVIO-B3teTIwD4nS7rOUkKl8v9SkzeZiadJMAgClf14-9-tAGrciC1rsfqINtvc";

            const app = initializeApp(firebaseConfig);
            const messaging = typeof window !== 'undefined' ? getMessaging(app) : null;

            export default function App() {
              const [token, setToken] = useState('');
                const [permission, setPermission] = useState(typeof Notification !== 'undefined' ? Notification.permission : 'default');
                  const [loadingToken, setLoadingToken] = useState(false);

                    // Solución a la falla lógica: Auto-cargar token si el permiso ya existe
                      useEffect(() => {
                          if (!messaging) return;

                              if (Notification.permission === 'granted') {
                                    fetchTokenSilently();
                                        }

                                            const unsubscribe = onMessage(messaging, (payload) => {
                                                  console.log('FCM Payload recibido:', payload);
                                                        sendSystemNotification(payload.notification.title, {
                                                                body: payload.notification.body,
                                                                        icon: '/vite.svg',
                                                                                ...payload.notification
                                                                                      });
                                                                                          });

                                                                                              return () => unsubscribe();
                                                                                                }, []);

                                                                                                  const fetchTokenSilently = async () => {
                                                                                                      setLoadingToken(true);
                                                                                                          try {
                                                                                                                const currentToken = await getToken(messaging, { vapidKey: VAPID_KEY });
                                                                                                                      if (currentToken) {
                                                                                                                              setToken(currentToken);
                                                                                                                                    } else {
                                                                                                                                            console.warn("No se pudo obtener el token silenciosamente.");
                                                                                                                                                  }
                                                                                                                                                      } catch (err) {
                                                                                                                                                            console.error("Fallo al recuperar token en segundo plano:", err);
                                                                                                                                                                }
                                                                                                                                                                    setLoadingToken(false);
                                                                                                                                                                      };

                                                                                                                                                                        const requestPermission = async () => {
                                                                                                                                                                            try {
                                                                                                                                                                                  setLoadingToken(true);
                                                                                                                                                                                        const status = await Notification.requestPermission();
                                                                                                                                                                                              setPermission(status);
                                                                                                                                                                                                    if (status === 'granted') {
                                                                                                                                                                                                            const currentToken = await getToken(messaging, { vapidKey: VAPID_KEY });
                                                                                                                                                                                                                    if (currentToken) setToken(currentToken);
                                                                                                                                                                                                                          }
                                                                                                                                                                                                                              } catch (err) {
                                                                                                                                                                                                                                    console.error("Fallo de permisos:", err);
                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                            setLoadingToken(false);
                                                                                                                                                                                                                                              };

                                                                                                                                                                                                                                                const sendSystemNotification = async (title, options) => {
                                                                                                                                                                                                                                                    if (permission !== 'granted') return;

                                                                                                                                                                                                                                                        if ('serviceWorker' in navigator) {
                                                                                                                                                                                                                                                              const registrations = await navigator.serviceWorker.getRegistrations();
                                                                                                                                                                                                                                                                    if (registrations.length > 0) {
                                                                                                                                                                                                                                                                            await registrations[0].showNotification(title, options);
                                                                                                                                                                                                                                                                                    return;
                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                  new Notification(title, options);
                                                                                                                                                                                                                                                                                                    };

                                                                                                                                                                                                                                                                                                      const modes = [
                                                                                                                                                                                                                                                                                                          {
                                                                                                                                                                                                                                                                                                                id: 'instant',
                                                                                                                                                                                                                                                                                                                      title: 'Modo Directo',
                                                                                                                                                                                                                                                                                                                            desc: 'Alerta estándar en la bandeja',
                                                                                                                                                                                                                                                                                                                                  icon: <Bell className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                        color: 'bg-blue-500',
                                                                                                                                                                                                                                                                                                                                              action: () => sendSystemNotification("Sistema Activo", { body: "Prueba local superada." })
                                                                                                                                                                                                                                                                                                                                                  },
                                                                                                                                                                                                                                                                                                                                                      {
                                                                                                                                                                                                                                                                                                                                                            id: 'urgent',
                                                                                                                                                                                                                                                                                                                                                                  title: 'Alerta Crítica',
                                                                                                                                                                                                                                                                                                                                                                        desc: 'Vibración agresiva y prioridad máxima',
                                                                                                                                                                                                                                                                                                                                                                              icon: <ShieldAlert className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                                                                    color: 'bg-red-500',
                                                                                                                                                                                                                                                                                                                                                                                          action: () => sendSystemNotification("⚠️ INTRUSIÓN", { 
                                                                                                                                                                                                                                                                                                                                                                                                  body: "Detectado acceso no autorizado.",
                                                                                                                                                                                                                                                                                                                                                                                                          requireInteraction: true,
                                                                                                                                                                                                                                                                                                                                                                                                                  vibrate: [500, 250, 500, 250, 500, 250, 500]
                                                                                                                                                                                                                                                                                                                                                                                                                        })
                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                      id: 'interactive',
                                                                                                                                                                                                                                                                                                                                                                                                                                            title: 'Modo Interactivo',
                                                                                                                                                                                                                                                                                                                                                                                                                                                  desc: 'Incluye botones de respuesta',
                                                                                                                                                                                                                                                                                                                                                                                                                                                        icon: <MessageSquareWarning className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                                                                                                                                              color: 'bg-indigo-500',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    action: () => sendSystemNotification("Autorización requerida", { 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            body: "¿Permitir despliegue en servidor 2?",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    actions: [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              { action: 'yes', title: '✅ Aprobar' },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { action: 'no', title: '❌ Denegar' }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    id: 'media',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          title: 'Modo Multimedia',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                desc: 'Inyecta una imagen de cámara',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      icon: <ImageIcon className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            color: 'bg-emerald-500',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  action: () => sendSystemNotification("Captura de Seguridad", { 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          body: "Movimiento detectado en sector sur.",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  image: "https://picsum.photos/600/300"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      id: 'silent',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            title: 'Modo Fantasma',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  desc: 'Llega sin sonido ni vibración',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        icon: <VolumeX className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              color: 'bg-slate-600',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    action: () => sendSystemNotification("Sincronización oculta", { 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            body: "Datos descargados en segundo plano.",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    silent: true
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        id: 'delay',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              title: 'Trigger Diferido',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    desc: 'Impacta después de 5 segundos',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          icon: <Clock className="w-6 h-6" />,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                color: 'bg-amber-500',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      action: () => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              setTimeout(() => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        sendSystemNotification("Tarea Finalizada", { body: "El script terminó de compilar." });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }, 5000);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ];

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="min-h-screen bg-zinc-950 text-zinc-100 p-6 font-sans">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="max-w-2xl mx-auto space-y-8">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <header className="flex items-center justify-between">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <h1 className="text-4xl font-black tracking-tighter text-white">FCM STUDIO</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <p className="text-zinc-500">Pruebas Locales y Tokenización</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className={`px-4 py-1 rounded-full text-xs font-bold uppercase tracking-widest ${permission === 'granted' ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-red-500/10 text-red-500 border border-red-500/20'}`}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {permission === 'granted' ? 'Conectado' : 'Sin Acceso'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </header>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {permission !== 'granted' && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="bg-indigo-600 rounded-2xl p-6 shadow-2xl shadow-indigo-500/20 flex flex-col items-center text-center space-y-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <BellRing className="w-12 h-12 text-white animate-bounce" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h2 className="text-xl font-bold text-white">Activar Permisos</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <p className="text-indigo-100 text-sm">El SO necesita autorización para el Service Worker.</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button onClick={requestPermission} disabled={loadingToken} className="bg-white text-indigo-600 px-8 py-3 rounded-xl font-bold hover:bg-indigo-50 transition-colors w-full sm:w-auto disabled:opacity-50">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {loadingToken ? 'Conectando con Google...' : 'Autorizar Dispositivo'}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {modes.map((mode) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              key={mode.id}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            onClick={mode.action}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className="group bg-zinc-900 border border-zinc-800 p-5 rounded-2xl text-left hover:border-zinc-600 transition-all hover:scale-[1.02] active:scale-95 flex flex-col items-start"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className={`${mode.color} w-10 h-10 rounded-xl flex items-center justify-center mb-4 shadow-lg group-hover:rotate-12 transition-transform`}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {mode.icon}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <h3 className="font-bold text-sm text-white">{mode.title}</h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-zinc-500 text-[11px] mt-1">{mode.desc}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div className="bg-zinc-900 border border-zinc-800 rounded-2xl p-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="flex items-center justify-between mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="flex items-center gap-2 text-zinc-400">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <Terminal className="w-4 h-4" />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <span className="text-xs font-mono uppercase">Token FCM de este dispositivo</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {permission === 'granted' && !token && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <button onClick={fetchTokenSilently} className="text-indigo-400 hover:text-indigo-300 flex items-center gap-1 text-xs">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <RefreshCw className={`w-3 h-3 ${loadingToken ? 'animate-spin' : ''}`} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Forzar Token
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="bg-black p-4 rounded-lg border border-zinc-800 text-[11px] font-mono text-indigo-400 break-all min-h-[50px] selection:bg-indigo-500/30">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {loadingToken ? "Generando token criptográfico..." : (token || "Error lógico: Permisos otorgados pero token no generado. Presiona 'Forzar Token'.")}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }